{"code": "import re

clinical_data = env['data_1']
mutation_data = env['data_2']

mutated_barcodes = {row['ParticipantBarcode'] for row in mutation_data}

histology_counts = {}
histology_mutations = {}

for row in clinical_data:
    desc = row.get('Patient_description', '')
    hist_type = row.get('histological_type', '')

    if not hist_type or hist_type.startswith('['):
        continue

    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if match:
        barcode = match.group()

        if hist_type not in histology_counts:
            histology_counts[hist_type] = 0
            histology_mutations[hist_type] = 0

        histology_counts[hist_type] += 1
        if barcode in mutated_barcodes:
            histology_mutations[hist_type] += 1

results = []
for hist_type in histology_counts:
    total = histology_counts[hist_type]
    mutated = histology_mutations[hist_type]
    pct = (mutated / total) * 100
    results.append((hist_type, pct, mutated, total))

results.sort(key=lambda x: x[1], reverse=True)
for r in results[:5]:
    print(f"{r[0]}: {r[1]:.2f}% ({r[2]}/{r[3]})")
"}

